-- gameserver reference/content data — classes, spells, monsters, items,
-- species, and the built-in adventure modules/maps. Generated from the
-- live database via:
--   mysqldump --no-create-info --complete-insert gameserver <tables...>
--
-- Deliberately excludes user/runtime tables (users, characters,
-- character_inventory, character_features, character_feats,
-- character_armor, character_items, character_multiclass_levels) —
-- those start empty; accounts and characters are created through the app.
--
-- The built-in modules (The Arena, Starter Dungeon) seed with
-- owner_user_id = NULL (no user exists yet on a fresh install). They're
-- playable immediately but not editable via the map editor until an
-- owner is assigned:
--   UPDATE adventure_modules SET owner_user_id = <id> WHERE owner_user_id IS NULL;
--
-- Run after db/schema.sql: mysql -u root gameserver < db/seed.sql



