INSERT INTO `classes` (`id`, `name`, `primary_ability`, `hit_die`, `saving_throw_proficiencies`, `skill_proficiencies`, `weapon_proficiencies`, `tool_proficiencies`, `armor_training`, `starting_equipment`, `becoming_text`, `created_at`, `updated_at`) VALUES (1,'Barbarian','Strength','D12 per Barbarian level','Strength and Constitution','Choose 2: Animal Handling, Athletics, Intimidation, Nature, Perception, or Survival','Simple and Martial weapons',NULL,'Light and Medium armor and Shields','Choose A or B: (A) Greataxe, 4 Handaxes, Explorer\'s Pack, and 15 GP; or (B) 75 GP','#### As a Level 1 Character\n\n• Gain all the traits in the Core Barbarian Traits table.\n\n• Gain the Barbarian\'s level 1 features, which are listed in the Barbarian Features table.\n\n#### As a Multiclass Character\n\n• Gain the following traits from the Core Barbarian Traits table: Hit Point Die, proficiency with Martial weapons, and training with Shields.\n• Gain the Barbarian\'s level 1 features, which are listed in the Barbarian Features table.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(2,'Bard','Charisma','D8 per Bard level','Dexterity and Charisma','Choose any 3 skills (see Playing the Game)','Simple weapons','Choose 3 Musical Instruments (see Equipment)','Light armor','Choose A or B: (A) Leather Armor, 2 Daggers, Musical Instrument of your choice, Entertainer\'s Pack, and 19 GP; or (B) 90 GP','#### As a Level 1 Character\n\n• Gain all the traits in the Core Bard Traits table.\n\n• Gain the Bard\'s level 1 features, which are listed in the Bard Features table.\n\n#### As a Multiclass Character\n\n• Gain the following traits from the Core Bard Traits table: Hit Point Die, proficiency in one skill of your choice, proficiency with one Musical Instrument of your choice, and training with Light armor.\n• Gain the Bard\'s level 1 features, which are listed in the Bard Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(3,'Cleric','Wisdom','D8 per Cleric level','Wisdom and Charisma','Choose 2: History, Insight, Medicine, Persuasion, or Religion','Simple weapons',NULL,'Light and Medium armor and Shields','Choose A or B: (A) Chain Shirt, Shield, Mace, Holy Symbol, Priest\'s Pack, and 7 GP; or (B) 110 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Cleric Traits table.\n- Gain the Cleric\'s level 1 features, which are listed in the Cleric Features table.\n\n#### As a Multiclass Character\n\n- Gain the following traits from the Core Cleric Traits table: Hit Point Die and training with Light and Medium armor and Shields.\n- Gain the Cleric\'s level 1 features, which are listed in the Cleric Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(4,'Druid','Wisdom','D8 per Druid level','Intelligence and Wisdom','Choose 2: Animal Handling, Arcana, Insight, Medicine, Nature, Perception, Religion, or Survival','Simple weapons','Herbalism Kit','Light armor and Shields','Choose A or B: (A) Leather Armor, Shield, Sickle, Druidic Focus (Quarterstaff), Explorer\'s Pack, Herbalism Kit, and 9 GP; or (B) 50 GP','#### As a Level 1 Character\n\n• Gain all the traits in the Core Druid Traits table.\n• Gain the Druid\'s level 1 features, which are listed in the Druid Features table.\n\n#### As a Multiclass Character\n\n• Gain the following traits from the Core Druid Traits table: Hit Point Die and training with Light armor and Shields.\n• Gain the Druid\'s level 1 features, which are listed in the Druid Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(5,'Fighter','Strength or Dexterity','D10 per Fighter level','Strength and Constitution','Choose 2: Acrobatics, Animal Handling, Athletics, History, Insight, Intimidation, Persuasion, Perception, or Survival','Simple and Martial weapons',NULL,'Light, Medium, and Heavy armor and Shields','Choose A, B, or C: (A) Chain Mail, Greatsword, Flail, 8 Javelins, Dungeoneer\'s Pack, and 4 GP; (B) Studded Leather Armor, Scimitar, Shortsword, Longbow, 20 Arrows, Quiver, Dungeoneer\'s Pack, and 11 GP; or (C) 155 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Fighter Traits table.\n- Gain the Fighter\'s level 1 features, which are listed in the Fighter Features table.\n\n#### As a Multiclass Character\n\n- Gain the following traits from the Core Fighter Traits table: Hit Point Die, proficiency with Martial weapons, and training with Light and Medium armor and Shields.\n- Gain the Fighter\'s level 1 features, which are listed in the Fighter Features table.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(6,'Monk','Dexterity and Wisdom','D8 per Monk level','Strength and Dexterity','Choose 2: Acrobatics, Athletics, History, Insight, Religion, or Stealth','Simple weapons and Martial weapons that have the Light property','Choose one type of Artisan\'s Tools or Musical Instrument (see Equipment)','None','Choose A or B: (A) Spear, 5 Daggers, Artisan\'s Tools or Musical Instrument chosen for the tool proficiency above, Explorer\'s Pack, and 11 GP; or (B) 50 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Monk Traits table.\n- Gain the Monk\'s level 1 features, which are listed in the Monk Features table.\n\n#### As a Multiclass Character\n\n- Gain the Hit Point Die trait from the Core Monk Traits table.\n- Gain the Monk\'s level 1 features, which are listed in the Monk Features table.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(7,'Paladin','Strength and Charisma','D10 per Paladin level','Wisdom and Charisma','Choose 2: Athletics, Insight, Intimidation, Medicine, Persuasion, or Religion','Simple and Martial weapons',NULL,'Light, Medium, and Heavy armor and Shields','Choose A or B: (A) Chain Mail, Shield, Longsword, 6 Javelins, Holy Symbol, Priest\'s Pack, and 9 GP; or (B) 150 GP','#### As a Level 1 Character\n\n• Gain all the traits in the Core Paladin Traits table.\n\n• Gain the Paladin\'s level 1 features, which are listed in the Paladin Features table.\n\n#### As a Multiclass Character\n\n• Gain the following traits from the Core Paladin Traits table: Hit Point Die, proficiency with Martial weapons, and training with Light and Medium armor and Shields.\n\n• Gain the Paladin\'s level 1 features, which are listed in the Paladin Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(8,'Ranger','Dexterity and Wisdom','D10 per Ranger level','Strength and Dexterity','Choose 3: Animal Handling, Athletics, Insight, Investigation, Nature, Perception, Stealth, or Survival','Simple and Martial weapons',NULL,'Light and Medium armor and Shields','Choose A or B: (A) Studded Leather Armor, Scimitar, Shortsword, Longbow, 20 Arrows, Quiver, Druidic Focus (sprig of mistletoe), Explorer\'s Pack, and 7 GP; or (B) 150 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Ranger Traits table.\n- Gain the Ranger\'s level 1 features, which are listed in the Ranger Features table.\n\n#### As a Multiclass Character\n\n- Gain the following traits from the Core Ranger Traits table: Hit Point Die, proficiency with Martial weapons, proficiency in one skill of your choice from the Ranger\'s skill list, and training with Light and Medium armor and Shields.\n- Gain the Ranger\'s level 1 features, which are listed in the Ranger Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(9,'Rogue','Dexterity','D8 per Rogue level','Dexterity and Intelligence','Choose 4: Acrobatics, Athletics, Deception, Insight, Intimidation, Investigation, Perception, Persuasion, Sleight of Hand, or Stealth','Simple weapons and Martial weapons that have the Finesse or Light property','Thieves\' Tools','Light armor','Choose A or B: (A) Leather Armor, 2 Daggers, Shortsword, Shortbow, 20 Arrows, Quiver, Thieves\' Tools, Burglar\'s Pack, and 8 GP; or (B) 100 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Rogue Traits table.\n- Gain the Rogue\'s level 1 features, which are listed in the Rogue Features table.\n\n#### As a Multiclass Character\n\n- Gain the following traits from the Core Rogue Traits table: Hit Point Die, proficiency in one skill of your choice from the Rogue\'s skill list, proficiency with Thieves\' Tools, and training with Light armor.\n- Gain the Rogue\'s level 1 features, which are listed in the Rogue Features table.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(10,'Sorcerer','Charisma','D6 per Sorcerer level','Constitution and Charisma','Choose 2: Arcana, Deception, Insight, Intimidation, Persuasion, or Religion','Simple weapons',NULL,'None','Choose A or B: (A) Spear, 2 Daggers, Arcane Focus (crystal), Dungeoneer\'s Pack, and 28 GP; or (B) 50 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Sorcerer Traits table.\n- Gain the Sorcerer\'s level 1 features, which are listed in the Sorcerer Features table.\n\n#### As a Multiclass Character\n\n- Gain the Hit Point Die from the Core Sorcerer Traits table.\n- Gain the Sorcerer\'s level 1 features, which are listed in the Sorcerer Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(11,'Warlock','Charisma','D8 per Warlock level','Wisdom and Charisma','Choose 2: Arcana, Deception, History, Intimidation, Investigation, Nature, or Religion','Simple weapons',NULL,'Light armor','Choose A or B: (A) Leather Armor, Sickle, 2 Daggers, Arcane Focus (orb), Book (occult lore), Scholar\'s Pack, and 15 GP; or (B) 100 GP','#### As a Level 1 Character\n\n- Gain all the traits in the Core Warlock Traits table.\n- Gain the Warlock\'s level 1 features, which are listed in the Warlock Features table.\n\n#### As a Multiclass Character\n\n- Gain the following traits from the Core Warlock Traits table: Hit Point Die and training with Light armor.\n- Gain the Warlock\'s level 1 features, which are listed in the Warlock Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01'),(12,'Wizard','Intelligence','D6 per Wizard level','Intelligence and Wisdom','Choose 2: Arcana, History, Insight, Investigation, Medicine, Nature, or Religion','Simple weapons',NULL,'None','Choose A or B: (A) 2 Daggers, Arcane Focus (Quarterstaff), Robe, Spellbook, Scholar\'s Pack, and 5 GP; or (B) 55 GP','#### As a Level 1 Character\n\n• Gain all the traits in the Core Wizard Traits table.\n• Gain the Wizard\'s level 1 features, which are listed in the Wizard Features table.\n\n#### As a Multiclass Character\n\n• Gain the Hit Point Die from the Core Wizard Traits table.\n• Gain the Wizard\'s level 1 features, which are listed in the Wizard Features table. See the multiclassing rules in \"Character Creation\" to determine your available spell slots.','2026-07-05 19:07:01','2026-07-05 19:07:01');
