INSERT INTO `weapons` (`id`, `name`, `category`, `weapon_type`, `damage`, `damage_dice`, `damage_type`, `properties`, `mastery`, `weight`, `cost`, `created_at`, `updated_at`) VALUES (1,'Club','Simple','Melee','1d4 Bludgeoning','1d4','Bludgeoning','Light','Slow','2 lb.','1 SP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(2,'Dagger','Simple','Melee','1d4 Piercing','1d4','Piercing','Finesse, Light, Thrown (Range 20/60)','Nick','1 lb.','2 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(3,'Greatclub','Simple','Melee','1d8 Bludgeoning','1d8','Bludgeoning','Two-Handed','Push','10 lb.','2 SP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(4,'Handaxe','Simple','Melee','1d6 Slashing','1d6','Slashing','Light, Thrown (Range 20/60)','Vex','2 lb.','5 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(5,'Javelin','Simple','Melee','1d6 Piercing','1d6','Piercing','Thrown (Range 30/120)','Slow','2 lb.','5 SP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(6,'Light Hammer','Simple','Melee','1d4 Bludgeoning','1d4','Bludgeoning','Light, Thrown (Range 20/60)','Nick','2 lb.','2 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(7,'Mace','Simple','Melee','1d6 Bludgeoning','1d6','Bludgeoning','—','Sap','4 lb.','5 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(8,'Quarterstaff','Simple','Melee','1d6 Bludgeoning','1d6','Bludgeoning','Versatile (1d8)','Topple','4 lb.','2 SP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(9,'Sickle','Simple','Melee','1d4 Slashing','1d4','Slashing','Light','Nick','2 lb.','1 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(10,'Spear','Simple','Melee','1d6 Piercing','1d6','Piercing','Thrown (Range 20/60), Versatile (1d8)','Sap','3 lb.','1 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(11,'Dart','Simple','Ranged','1d4 Piercing','1d4','Piercing','Finesse, Thrown (Range 20/60)','Vex','1/4 lb.','5 CP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(12,'Light Crossbow','Simple','Ranged','1d8 Piercing','1d8','Piercing','Ammunition (Range 80/320; Bolt), Loading, Two-Handed','Slow','5 lb.','25 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(13,'Shortbow','Simple','Ranged','1d6 Piercing','1d6','Piercing','Ammunition (Range 80/320; Arrow), Two-Handed','Vex','2 lb.','25 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(14,'Sling','Simple','Ranged','1d4 Bludgeoning','1d4','Bludgeoning','Ammunition (Range 30/120; Bullet)','Slow','—','1 SP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(15,'Battleaxe','Martial','Melee','1d8 Slashing','1d8','Slashing','Versatile (1d10)','Topple','4 lb.','10 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(16,'Flail','Martial','Melee','1d8 Bludgeoning','1d8','Bludgeoning','—','Sap','2 lb.','10 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(17,'Glaive','Martial','Melee','1d10 Slashing','1d10','Slashing','Heavy, Reach, Two-Handed','Graze','6 lb.','20 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(18,'Greataxe','Martial','Melee','1d12 Slashing','1d12','Slashing','Heavy, Two-Handed','Cleave','7 lb.','30 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(19,'Greatsword','Martial','Melee','2d6 Slashing','2d6','Slashing','Heavy, Two-Handed','Graze','6 lb.','50 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(20,'Halberd','Martial','Melee','1d10 Slashing','1d10','Slashing','Heavy, Reach, Two-Handed','Cleave','6 lb.','20 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(21,'Lance','Martial','Melee','1d10 Piercing','1d10','Piercing','Heavy, Reach, Two-Handed (unless mounted)','Topple','6 lb.','10 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(22,'Longsword','Martial','Melee','1d8 Slashing','1d8','Slashing','Versatile (1d10)','Sap','3 lb.','15 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(23,'Maul','Martial','Melee','2d6 Bludgeoning','2d6','Bludgeoning','Heavy, Two-Handed','Topple','10 lb.','10 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(24,'Morningstar','Martial','Melee','1d8 Piercing','1d8','Piercing','—','Sap','4 lb.','15 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(25,'Pike','Martial','Melee','1d10 Piercing','1d10','Piercing','Heavy, Reach, Two-Handed','Push','18 lb.','5 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(26,'Rapier','Martial','Melee','1d8 Piercing','1d8','Piercing','Finesse','Vex','2 lb.','25 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(27,'Scimitar','Martial','Melee','1d6 Slashing','1d6','Slashing','Finesse, Light','Nick','3 lb.','25 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(28,'Shortsword','Martial','Melee','1d6 Piercing','1d6','Piercing','Finesse, Light','Vex','2 lb.','10 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(29,'Trident','Martial','Melee','1d8 Piercing','1d8','Piercing','Thrown (Range 20/60), Versatile (1d10)','Topple','4 lb.','5 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(30,'Warhammer','Martial','Melee','1d8 Bludgeoning','1d8','Bludgeoning','Versatile (1d10)','Push','5 lb.','15 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(31,'War Pick','Martial','Melee','1d8 Piercing','1d8','Piercing','Versatile (1d10)','Sap','2 lb.','5 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(32,'Whip','Martial','Melee','1d4 Slashing','1d4','Slashing','Finesse, Reach','Slow','3 lb.','2 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(33,'Blowgun','Martial','Ranged','1 Piercing',NULL,NULL,'Ammunition (Range 25/100; Needle), Loading','Vex','1 lb.','10 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(34,'Hand Crossbow','Martial','Ranged','1d6 Piercing','1d6','Piercing','Ammunition (Range 30/120; Bolt), Light, Loading','Vex','3 lb.','75 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(35,'Heavy Crossbow','Martial','Ranged','1d10 Piercing','1d10','Piercing','Ammunition (Range 100/400; Bolt), Heavy, Loading, Two-Handed','Push','18 lb.','50 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(36,'Longbow','Martial','Ranged','1d8 Piercing','1d8','Piercing','Ammunition (Range 150/600; Arrow), Heavy, Two-Handed','Slow','2 lb.','50 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(37,'Musket','Martial','Ranged','1d12 Piercing','1d12','Piercing','Ammunition (Range 40/120; Bullet), Loading, Two-Handed','Slow','10 lb.','500 GP','2026-07-05 19:07:01','2026-07-05 19:07:01'),(38,'Pistol','Martial','Ranged','1d10 Piercing','1d10','Piercing','Ammunition (Range 30/90; Bullet), Loading','Vex','3 lb.','250 GP','2026-07-05 19:07:01','2026-07-05 19:07:01');
