INSERT INTO `items` (`id`, `name`, `item_type`, `description`, `weight`, `cost`, `created_at`, `updated_at`) VALUES (1,'Potion of Healing','consumable','Regain 2d4+2 hit points when consumed.','0.5 lb','50 gp','2026-07-07 00:53:40','2026-07-07 00:53:40'),(2,'Rations','consumable','One day of food.','2 lb','5 sp','2026-07-07 00:53:40','2026-07-07 00:53:40'),(3,'Torch','misc','Burns for 1 hour, providing bright light in a 20-foot radius.','1 lb','1 cp','2026-07-07 00:53:40','2026-07-07 00:53:40'),(4,'Rope (50 ft)','misc','Hempen rope, 50 feet.','10 lb','1 gp','2026-07-07 00:53:40','2026-07-07 00:53:40'),(5,'Gemstone','treasure','A small polished gemstone of no fixed value here — just something to sell.','-','-','2026-07-07 00:53:40','2026-07-07 00:53:40');
