INSERT INTO `adventure_modules` (`id`, `owner_user_id`, `slug`, `name`, `description`, `version`, `created_at`, `updated_at`) VALUES (14,NULL,'the-arena','The Arena','Battle to the death','1.0.0','2026-07-10 17:23:20','2026-07-11 00:31:47'),(15,NULL,'starter-dungeon','Starter Dungeon','A sprawling 128x128 introductory dungeon of interconnected chambers, crawling with level-appropriate foes.','1.0.0','2026-07-10 18:08:54','2026-07-11 00:31:47');
